var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇다, 방랑자여. <color=#ffd34c>이제까지</color>는 그래왔지.","JPN":"さよう、放浪者よ。<color=#ffd34c>今まで</color>はそうであった。","ENG":"Poor choice of words, Wayfarer. <color=#ffd34c>To this day</color>it has.","TWN":"沒錯，流浪者，<color=#ffd34c>一如往常</color>。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"현실의 공기를 마시며 지낸 자가, 왕께서 선별하신 자매들을 당해낼 수 있으리라 생각하느냐?","JPN":"現実の空気を吸い過ごした者が、王の選別された姉妹たちに勝てるとでも思ったか？","ENG":"Did you really think that one who relies on air in Normalside to breathe could ever overcome the sisters appointed by the queen?","TWN":"但你以為呼吸現世空氣的人，能夠招架王親自揀選的姊妹嗎？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"아직……! 아직이다……!","JPN":"まだ……！　まだだ……！","ENG":"Not...! Not yet...!","TWN":"我……！我還可以……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는, 아직……!","JPN":"我は、まだ……！","ENG":"I can still...!","TWN":"我還可以……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그런 피폐한 꼴로 자매들에게 저항한 것만은 칭찬해 주지.","JPN":"そのような疲弊した姿で姉妹たちに抗ったことは誉めてやろう。","ENG":"Your resistance despite your condition is commendable.","TWN":"光是看你用那副狼狽的模樣在抵抗，就很值得稱讚。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"허나 제 힘도 쓰지 못하고 녹슨 갑주에 의지하면서 왕의 이름을 능멸한 죄…….","JPN":"だが己の力も使えず、錆びた甲冑に頼りながら王の名を侮辱した罪……","ENG":"But the crime of sullying the queen’s name while relying on the power of a rusty old armor...","TWN":"不過無法發揮自己的能力，只靠那副破爛鎧甲，就想藐視王的罪……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"죽음을 면할 수 없겠구나.","JPN":"死は免れぬ。","ENG":"Your sentence can be nothing but death.","TWN":"我看是死罪難逃！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"네 놈……. 솔리키타티오…….","JPN":"貴様……ソリキタティオ……","ENG":"Damn you... Sollicitatio...","TWN":"你這傢伙……索爾奇塔提奧……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"축복을 거부한 끝에 결국 진창에 처박히고 말았구나.","JPN":"祝福を拒んだ末に、結局ぬかるみにはまるか。","ENG":"You refused to receive the blessing and now you crawl in the mud.","TWN":"拒絕祝福，結果卻落得如此下場。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이제 끝이다. 마지막 순간까지 너의 불경함을…… ","JPN":"これでしまいだ。最後まで貴様の不敬を…… ","ENG":"It ends now. Right until your last moment, I couldn’t fix your... ","TWN":"都結束了，雖然到最後都無法矯正你的狂妄……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_NULL","text":{"KOREA":"처형의 검이 준비되었습니다, 자매님. 허락을.","JPN":"処刑の剣の準備ができました、お姉様。許可を。","ENG":"The execution sword has been prepared, sister. With your permission?","TWN":"行刑之劍已經備妥，等候您一聲令下。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아니. 돌아가야 한다. 왕께서 부르셨으니.","JPN":"いや。帰らねばならぬ。王がお呼びだ。","ENG":"No. We must go back. The queen summons us.","TWN":"不，回去吧，王召喚我們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"타기리온이……? 어째서…….","JPN":"タギリオンが……？　なぜ……","ENG":"Thagirion...? But why...","TWN":"塔基里翁……？怎麼會……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 자비를 감사히 여겨라. 방랑자여.","JPN":"王の慈悲に感謝しろ。放浪者よ。","ENG":"Rejoice, for the queen is merciful, Wayfarer.","TWN":"流浪者，你要感謝王的憐憫。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아마도 너의 추태를 더 오래 감상하길 원하시나 보구나.","JPN":"おそらくお前の醜態をもっとご覧になりたいのであろう。","ENG":"Perhaps your indecent behavior is found amusing.","TWN":"可能是王想要再多欣賞一下你的醜態吧？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};